// Gate: skip if outside send hours or over rate limit.
const h = new Date().getHours();
const start = parseInt($env.SEND_HOUR_START || '9');
const end = parseInt($env.SEND_HOUR_END || '18');
if (h < start || h >= end) {
  return []; // empty -> downstream does nothing
}
return [{ json: { ok: true } }];

// Decide what budget is left today
const row = items[0].json;
const connLimit = parseInt($env.DAILY_LI_CONNECTION_LIMIT || '20');
const msgLimit  = parseInt($env.DAILY_LI_MESSAGE_LIMIT || '40');
const connLeft = Math.max(0, connLimit - (row.conn_today || 0));
const msgLeft  = Math.max(0, msgLimit  - (row.msgs_today || 0));
if (connLeft === 0 && msgLeft === 0) return [];
return [{ json: { connLeft, msgLeft } }];

// Render template for this touch_type, replacing {{placeholders}} from lead data + .env.
// Uses fs to read templates/linkedin-templates/<touch_type>.txt
const fs = require('fs');
const path = require('path');
const dir = $env.TEMPLATE_DIR;
const out = [];
for (const it of items) {
  const touch = it.json.next_touch;
  const fname = touch === 'connection_request' ? 'connection-note.txt'
             : touch === 'first_message'       ? 'first-message.txt'
             : touch === 'follow_up_1'         ? 'follow-up-1.txt'
             : touch === 'follow_up_2'         ? 'follow-up-2.txt'
             : null;
  if (!fname) continue;
  const raw = fs.readFileSync(path.join(dir, fname), 'utf8');
  const firstName = (it.json.contact_name || '').split(' ')[0];
  const rendered = raw
    .replace(/\{\{firstName\}\}/g, firstName)
    .replace(/\{\{fullName\}\}/g, it.json.contact_name || '')
    .replace(/\{\{title\}\}/g, it.json.title || '')
    .replace(/\{\{company\}\}/g, it.json.company_name || '')
    .replace(/\{\{senderFirstName\}\}/g, $env.SENDER_FIRST_NAME || '')
    .replace(/\{\{senderFullName\}\}/g, $env.SENDER_FULL_NAME || '')
    .replace(/\{\{senderTitle\}\}/g, $env.SENDER_TITLE || '')
    .replace(/\{\{senderCompany\}\}/g, $env.SENDER_COMPANY || '')
    .replace(/\{\{calendarUrl\}\}/g, $env.SENDER_CALENDAR_URL || '')
    .replace(/\{\{productPitch\}\}/g, $env.PRODUCT_PITCH || '')
    .replace(/\{\{connectionNoteHook\}\}/g, $env.CONNECTION_NOTE_HOOK || '')
    .replace(/\{\{firstMessageHook\}\}/g, $env.FIRST_MESSAGE_HOOK || '')
    .replace(/\{\{privacyNoticeUrl\}\}/g, $env.PRIVACY_NOTICE_URL || '');
  out.push({ json: { ...it.json, rendered_body: rendered, template_used: fname } });
}
return out;
